mapper.select:
select concat('20', #{year}) as year, count(*) as totCnt
from statistic.request_info ri
where left(ri.create_date, 2) = #{year};

select concat('20', #{yearMonth}) as yearMonth, count(*) as totCnt
from statistic.request_info ri
where left(ri.create_date, 4) = #{yearMonth};

select avg(dailyCount) as averageDailyLogin, count(*) as totalDays, sum(dailyCount) as totalLogins
from (
    select date_format(ll.login_at, '%Y-%m-%d') as loginDate, count(distinct ll.member_id) as dailyCount
    from statistic.login_log ll
    where ll.login_at between #{startDate} and #{endDate}
    group by date_format(ll.login_at, '%Y-%m-%d')
) daily
